        "Diag_Path_Invalid_Sug": [.en: "The directory does not exist. Check for typos or remove the entry.", .zh: "该目录不存在。请检查拼写或移除该项。", .zh_Hant: "該目錄不存在。請檢查拼寫或移除該項。", .ko: "디렉토리가 존재하지 않습니다. 오타를 확인하거나 항목을 제거하세요.", .ja: "ディレクトリが存在しません。タイポを確認するか、エントリを削除してください。", .fr: "Le répertoire n'existe pas. Vérifiez les fautes de frappe ou supprimez l'entrée.", .de: "Das Verzeichnis existiert nicht. Überprüfen Sie auf Tippfehler oder entfernen Sie den Eintrag.", .fi: "Hakemistoa ei ole olemassa. Tarkista kirjoitusvirheet tai poista merkintä.", .ru: "Каталог не существует. Проверьте опечатки или удалите запись."],
        "Diag_Orphaned_File": [.en: "Orphaned config file found: ", .zh: "发现孤立的配置文件: ", .zh_Hant: "發現孤立的配置文件: ", .ko: "분리된 설정 파일 발견: ", .ja: "孤立した構成ファイルが見つかりました: ", .fr: "Fichier de configuration orphelin trouvé : ", .de: "Verwaiste Konfigurationsdatei gefunden: ", .fi: "Löytyi orpo asetustiedosto: ", .ru: "Найден потерянный файл конфигурации: "],
