        "Missing 'command not found'?": [.en: "Missing 'command not found'?", .zh: "终端报错 'command not found'？", .zh_Hant: "終端報錯 'command not found'？", .ko: "'command not found' 오류가 발생하나요?", .ja: "'command not found' エラーが表示されますか？", .fr: "'command not found' manquant ?", .de: "'command not found' fehlt?", .fi: "Puuttuuko 'command not found'?", .ru: "Отсутствует 'command not found'?"],
